import type { StageInput, StageOutput, StageRuntime } from '../contracts.js';

export async function runStage(input: StageInput, runtime: StageRuntime): Promise<StageOutput> {
  const facts = parseFacts(input.domain['inputs.user_text']);
  const plan = String(facts.plan ?? 'pro');
  const seats = Number(facts.seats ?? 12);
  const region = String(facts.region ?? 'us');
  const base = plan === 'enterprise' ? 500 : plan === 'pro' ? 100 : 40;
  const seatRate = plan === 'enterprise' ? 12 : plan === 'pro' ? 7 : 5;
  const subtotal = base + seats * seatRate;
  const multiplier = region === 'eu' ? 1.2 : 1;
  const total = Math.round(subtotal * multiplier);
  return {
    result_json: JSON.stringify({
      stage: input.stage,
      plan,
      seats,
      region,
      base_usd: base,
      seat_rate_usd: seatRate,
      subtotal_usd: subtotal,
      region_multiplier: multiplier,
      total_usd: total,
      currency: 'USD',
      priced_at: runtime.now(),
    }),
    items_json: JSON.stringify(['plan:' + plan, 'seats:' + seats, 'total_usd:' + total]),
    digest: '',
  };
}

function parseFacts(value: unknown): Record<string, unknown> {
  if (typeof value !== 'string') return {};
  try {
    const parsed = JSON.parse(value) as unknown;
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed as Record<string, unknown> : {};
  } catch {
    return {};
  }
}
